const history = $input.all();

// Filter: Isolate comment history for validation checks
const comments_history = history.filter(x => x.type === "commentCard");

// [REDACTED]: Configuration for mapping list IDs to names
const actions_list = [
  { list_id: "ID_001", list_name: "List Name 1" },
  // ...
];

// [REDACTED]: Configuration for valid move rules and required comments
const valid_move = [
  { action: "List A -> List B", valid_comment: "specific text required" },
  // ...
];

const result = [];

// Main Processing Loop
FOR each item IN history:
  INITIALIZE validation flag (valid = false);

  // 1. Initial Data Extraction
  EXTRACT id, data, type, member, date, memberIds;
  DECLARE variables: actions, beforeAction, afterAction, currentStatus;

  // 2. Exclusion Logic
  IF data.old.idLabels changed OR date is before today:
    SKIP iteration (continue);

  // 3. Processing "Update" Events (data.old exists)
  IF data.old exists:

    // Case A: Card Moved Between Lists
    IF type is 'updateCard' AND list changed:
      MAP list IDs to names using 'actions_list';
      SET actions = "Old List -> New List";
      SET currentStatus = New List;

      // Validation: Check if move is allowed based on comment history
      RETRIEVE comments for this card ID;
      FIND rule in 'valid_move' matching this action;
      IF rule exists:
        CHECK if any comment contains the 'valid_comment' string;
        SET valid = true if match found;

    // Case B: Card Position Changed within List
    ELSE IF type is 'updateCard' AND position changed:
      SET actions = "CARDS POSITION CHANGE";
      SET currentStatus = current list name;
      // Note: valid remains false (default)

    // Case C: Description Modified
    ELSE IF type is 'updateCard' AND description changed:
      SET actions = "DESCRIPTION MODIFIED";
      SET beforeAction = old description;
      SET afterAction = new description;
      SET currentStatus = current list name;

  // 4. Processing "Create/Comment" Events (data.old does not exist)
  ELSE:

    // Case D: New Comment Added
    IF type is "commentCard":
      SET actions = "NEW COMMENT";
      SET afterAction = comment text;
      SET currentStatus = list name;

    // Case E: New Card Added/Copied
    ELSE IF type is "moveCardToBoard" OR "copyCard":
      SET actions = "NEW CARD ADDED";
      SET afterAction = list name;
      SET currentStatus = list name;

  // 5. Final Output Construction
  IF valid is true:
    PUSH object to result array:
      - timestamp (ISO)
      - datetime (Formatted)
      - card details (id, name, shift)
      - action details (type, before/after)
      - member info (creator, ids)
      - metadata (description, labels);

RETURN result;

