// Helper: Markdown Sanitization
// Strips HTML and Markdown syntax to isolate raw text
function normalizeText(markdown) {
  IF input is empty RETURN empty string;

  REMOVE HTML tags (e.g., <div>, <br>);
  REMOVE Bold/Italic markers (e.g., **, __, *, _);
  REMOVE Inline code blocks (e.g., `code`);
  EXTRACT text from Links and Images (discard URLs);
  REMOVE Headers (e.g., # Header);
  REMOVE Blockquotes (e.g., > quote);
  REMOVE List markers (e.g., *, -, 1.);
  REMOVE Horizontal rules (e.g., ---);
  TRIM whitespace;

  RETURN clean text;
}

// Helper: Video Metadata Parser
// Extracts key-value pairs from a formatted description string
function getVideoInfo(text) {
  // Regex: Looks for **Key:** followed by value until next ** or end of string
  DEFINE regex pattern for key-value extraction;

  const results = {};
  ITERATE over all matches found in text:
    EXTRACT rawKey and rawValue;

    // Key Cleaning
    LOWERCASE key;
    REPLACE spaces/hyphens with underscores (e.g., "Video Title" -> "video_title");

    // Value Cleaning
    TRIM whitespace and newlines;

    // Validation
    IF value is empty or placeholder:
      ASSIGN empty string;
    ELSE:
      ASSIGN cleaned value;

  RETURN results object;
}

// Main Processing Loop
FOR each item IN items:
